      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const router = express.Router();
const tasksService = require('./service');
const { sendError } = require('../../lib/errors');

router.post('/', (req, res) => {
  const task = req.body;
  if (!task.name) {
    return sendError(res, 400, 'INVALID_PAYLOAD', 'Payload must include name');
  }

  const newTask = tasksService.createTask(req.projectId, { ...task, status: 'todo' });
  res.status(201).json({ task: newTask });
});

router.get('/', (req, res) => {
  const { status } = req.query;
  let tasks = tasksService.getAllTasks(req.projectId);
  if (status) {
    tasks = tasks.filter(t => t.status === status);
  }
  res.json({ tasks });
});

router.patch('/:taskId', (req, res) => {
  const { taskId } = req.params;
  const { status } = req.body;
  if (!['todo', 'done'].includes(status)) {
    return sendError(res, 400, 'INVALID_STATUS', 'Status must be either todo or done');
  }

  const task = tasksService.updateTask(req.projectId, taskId, { status });
  if (!task) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }

  res.json({ task });
});

module.exports = router;
