      "path": "src/modules/tasks/service.js",
      "content": "const { generateId } = require('../../lib/id');
const projectsService = require('../projects/service');

const createTask = (projectId, task) => {
  const project = projectsService.getProject(projectId);
  if (!project) {
    return null;
  }

  const newTask = { ...task, id: generateId() };
  project.tasks.push(newTask);
  projectsService.updateProject(project);

  return newTask;
};

const getAllTasks = (projectId) => {
  const project = projectsService.getProject(projectId);
  if (!project) {
    return [];
  }
  return project.tasks;
};

const updateTask = (projectId, taskId, updates) => {
  const project = projectsService.getProject(projectId);
  if (!project) {
    return null;
  }

  const taskIndex = project.tasks.findIndex(t => t.id === taskId);
  if (taskIndex === -1) {
    return null;
  }

  const updatedTask = { ...project.tasks[taskIndex], ...updates };
  project.tasks[taskIndex] = updatedTask;
  projectsService.updateProject(project);

  return updatedTask;
};

module.exports = { createTask, getAllTasks, updateTask };
